SELECT DISTINCT ?river WHERE {
  ?river a <http://dbpedia.org/ontology/River> .
  ?lake a <http://dbpedia.org/ontology/Lake> ;
        <http://dbpedia.org/ontology/inflow> ?river ;
        <http://dbpedia.org/ontology/country> <http://dbpedia.org/resource/Germany> .
}
UNION
{
  SELECT DISTINCT ?river WHERE {
    ?river a <http://dbpedia.org/ontology/River> .
