  OPTIONAL {
    ?river <http://dbpedia.org/ontology/length> ?length .
  }
  OPTIONAL {
    ?river <http://dbpedia.org/property/length> ?length .
  }
}
UNION
{
  SELECT DISTINCT ?lake WHERE {
    {
      ?lake a <http://dbpedia.org/ontology/Lake> ;
            <http://dbpedia.org/ontology/country> <http://dbpedia.org/resource/Denmark> .
