SELECT DISTINCT  ?company ?employees
WHERE
  {   { ?company  rdf:type  <http://dbpedia.org/ontology/Company>
          { ?company  <http://dbpedia.org/ontology/numberOfEmployees>  ?employees }
        UNION
          { ?company  <http://dbpedia.org/property/numEmployees>  ?employees }
        FILTER ( ?employees > 1000000 )
      }
    UNION
      { VALUES ?company { <http://dbpedia.org/resource/Google> <http://dbpedia.org/resource/IBM> }
          { ?company  <http://dbpedia.org/ontology/numberOfEmployees>  ?employees }
        UNION
          { ?company  <http://dbpedia.org/property/numEmployees>  ?employees }
      }
  }
ORDER BY ?company

